sql:
SELECT facility_name, description, capacity
FROM school_facilities
WHERE facility_type = 'Academic' AND capacity > 10;

SELECT type_name
FROM school_types
WHERE religious_affiliation = 'Christianity';

external_knowledge:
- "individuals" refers to users;
- "reviews" are associated with user IDs;
- "positive feedback" corresponds to "helpful_votes";
- "negative feedback" corresponds to "unhelpful_votes";
- "more than a handful" means more than 10 unhelpful votes.

sql:
SELECT u.user_name
FROM users u
INNER JOIN administrators a ON u.user_id = a.admin_id;

SELECT rating_name 
FROM ratings 
WHERE rating_id = 1;

SELECT country, MIN(location_id) AS first_location_id
FROM locations
GROUP BY country;

SELECT school_id, COUNT(*) as number_of_administrators
FROM administrators
GROUP BY school_id;

SELECT feature_id, school_id, feature_name, description, feature_type, frequency
FROM school_features
WHERE feature_type = 'Extracurricular' AND frequency = 'Weekly';

SELECT COUNT(*) 
FROM school_features 
WHERE feature_name = 'Sports';

SELECT COUNT(*) AS active_moderator_count
FROM moderators
WHERE start_date IS NOT NULL AND end_date IS NULL;

SELECT DISTINCT reviews.school_id
FROM reviews
WHERE reviews.rating < (SELECT AVG(rating) FROM reviews);
